<template>
  <div>
    <div style="width: 100%; height: 60px; background-color: #fff; padding: 0px 12px;" v-if="!loading || data.ratedContestantsCount !== 0">
      <p style="font-size: 22px; margin-bottom: 0; text-align: center;">{{ data.judgeName }}</p>
      <p style="font-size: 16px; margin-bottom: 0; text-align: center;">已评{{ data.ratedContestantsCount }}位选手<span v-if="data.ratedContestantsCount !== 0">，平均打分： {{ data.averageScore }}分</span></p>
    </div>
    <a-list :data-source="data.scoreDetails" :style="{ backgroundColor: data.scoreDetails.length > 0 ? '#fff' : '' }" style="margin-top: 24px;">
      <a-list-item slot="renderItem" slot-scope="item" style="padding: 20px 14px 16px;">
        <span slot="actions" style="font-size: 20px;" @click="route2Detail(item.contestantId)"><span style="color: #000; font-weight: 700;">{{ item.score }}分</span> ></span>
        <a-list-item-meta>
          <h2 slot="title" style="font-weight: 700;">{{ item.contestantName }}</h2>
          <div slot="description">
            <p style="color: blue; margin-bottom: 0; font-size: 14px;">权重分数：{{ item.weightedScore }}分</p>
            <p style="margin-bottom: 0; font-size: 14px;">提交时间： {{ item.scoreTime | time }}</p>
          </div>
        </a-list-item-meta>
      </a-list-item>
    </a-list>
  </div>
</template>
<script>
import { getJudgeScoreStatistics } from '@/api/scoreRecord'
export default {
  data() {
    return {
      data: {
        ratedContestantsCount: 0,
        scoreDetails: [],
      },
      loading: false,
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      getJudgeScoreStatistics(this.$route.params.id, this.$route.query.judgeId).then(res => {
        this.data = res
      })
    },
    route2Detail(cid) {
      this.$router.push({
        name: 'contestantVoteDataDetail',
        params: {
          judgeId: this.$route.query.judgeId,
          cid: cid,
        },
      })
    },
  },
}
</script>
